        memory1_0_in <=
            addsub0_0_out when "0",
            rec0_0_out when "1",
            (others => '-') when others;

    with memory2_0_sel select
        memory2_0_in <=
            addsub1_0_out when "000",
            addsub0_0_out when "001",
            mul1_0_out when "010",
            in0_0_out when "011",
            mul0_0_out when "100",
            (others => '-') when others;

    with memory3_0_sel select
        memory3_0_in <=
            in0_0_out when "00",
            addsub1_0_out when "01",
            mul1_0_out when "10",
            (others => '-') when others;

    with memory4_0_sel select
        memory4_0_in <=
            mul1_0_out when "00",
            addsub1_0_out when "01",
            addsub0_0_out when "10",
            neg0_0_out when "11",
            (others => '-') when others;

    with memory5_0_sel select
        memory5_0_in <=
            rec0_0_out when "00",
            in0_0_out when "01",
            mul0_0_out when "10",
            (others => '-') when others;

    memory6_0_in <= mul1_0_out;

end architecture rtl;


